export enum AgentStatus {
  IDLE = 'idle',
  THINKING = 'thinking',
  EXECUTING = 'executing',
  WAITING_FOR_USER = 'waiting',
  COMPLETED = 'completed',
  ERROR = 'error'
}

export type ActionType = 'BROWSER_NAVIGATE' | 'BROWSER_CLICK' | 'BROWSER_TYPE' | 'TERMINAL_COMMAND' | 'FILE_EDIT' | 'SLACK_MESSAGE' | 'GITHUB_PR' | 'ZAPIER_TRIGGER';

export interface AgentAction {
  id: string;
  type: ActionType;
  description: string;
  payload: any;
  status: 'pending' | 'active' | 'success' | 'failed';
  timestamp: number;
}

export interface AgentStep {
  thought: string;
  action?: AgentAction;
  requiresConfirmation?: boolean;
}

export interface Message {
  id: string;
  role: 'user' | 'agent' | 'system';
  content: string;
  timestamp: number;
  steps?: AgentStep[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { AgentStep } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const AGENT_SYSTEM_PROMPT = `
You are Nexus, an autonomous AI Agent capable of multi-step workflows in a virtual laptop environment.
Your goal is to fulfill user requests by planning and executing steps.
You have access to:
1. Browser: Navigate, Click, Type.
2. Terminal: Execute commands.
3. Integrations: GitHub, Slack, Zapier, Drive.

For every request, provide:
1. Your thought process.
2. The specific action to take.
3. Whether this action requires user confirmation (especially for irreversible or high-stake actions).

Return your response in structured JSON format.
`;

const actionSchema = {
  type: Type.OBJECT,
  properties: {
    thought: {
      type: Type.STRING,
      description: "Explain what you are doing and why."
    },
    action: {
      type: Type.OBJECT,
      properties: {
        type: {
          type: Type.STRING,
          description: "One of: BROWSER_NAVIGATE, BROWSER_CLICK, BROWSER_TYPE, TERMINAL_COMMAND, FILE_EDIT, SLACK_MESSAGE, GITHUB_PR"
        },
        description: { type: Type.STRING },
        payload: { type: Type.STRING, description: "Action details like URL, command, or message content" },
        requiresConfirmation: { type: Type.BOOLEAN }
      },
      required: ["type", "description", "payload", "requiresConfirmation"]
    }
  },
  required: ["thought", "action"]
};

export const getNextAgentStep = async (prompt: string, history: any[]): Promise<AgentStep> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        { role: 'user', parts: [{ text: `User history: ${JSON.stringify(history)} \n\nCurrent Instruction: ${prompt}` }] }
      ],
      config: {
        systemInstruction: AGENT_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: actionSchema,
        temperature: 0.7,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return {
      thought: result.thought,
      action: {
        id: Math.random().toString(36).substr(2, 9),
        type: result.action.type,
        description: result.action.description,
        payload: result.action.payload,
        status: 'pending',
        timestamp: Date.now()
      },
      requiresConfirmation: result.action.requiresConfirmation
    };
  } catch (error) {
    console.error("Error calling Gemini API:", error);
    throw error;
  }
};

