import React, { useState, useRef, useEffect } from 'react';
import { Send, CheckCircle, AlertCircle, Loader2, User, Bot, Play, Pause } from 'lucide-react';
import { Message, AgentStatus, AgentStep } from '../types';

interface AgentControlProps {
  messages: Message[];
  status: AgentStatus;
  onSendMessage: (content: string) => void;
  onApproveAction: () => void;
  onCancelAction: () => void;
}

const AgentControl: React.FC<AgentControlProps> = ({ 
  messages, 
  status, 
  onSendMessage, 
  onApproveAction, 
  onCancelAction 
}) => {
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, status]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputValue.trim() && status === AgentStatus.IDLE) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  const currentWaitingStep = messages.find(m => m.steps?.some(s => s.requiresConfirmation))?.steps?.find(s => s.requiresConfirmation);

  return (
    <div className="w-[400px] border-l border-slate-800 flex flex-col h-full bg-slate-950">
      {/* Header */}
      <div className="p-4 border-b border-slate-800 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="relative">
            <div className={`w-3 h-3 rounded-full ${
              status === AgentStatus.EXECUTING ? 'bg-green-500 animate-pulse' :
              status === AgentStatus.THINKING ? 'bg-indigo-500 animate-pulse' :
              status === AgentStatus.WAITING_FOR_USER ? 'bg-amber-500' : 'bg-slate-500'
            }`}></div>
            {status !== AgentStatus.IDLE && (
               <div className="absolute -inset-1 rounded-full border border-indigo-500/30 animate-ping"></div>
            )}
          </div>
          <div>
            <h2 className="font-semibold text-sm">Agent Nexus</h2>
            <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{status}</p>
          </div>
        </div>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 ${
              msg.role === 'user' ? 'bg-slate-800' : 'bg-indigo-600'
            }`}>
              {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
            </div>
            <div className={`max-w-[85%] ${msg.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-3 rounded-2xl text-sm ${
                msg.role === 'user' ? 'bg-slate-800 rounded-tr-none' : 'bg-slate-900 border border-slate-800 rounded-tl-none'
              }`}>
                {msg.content}
              </div>

              {msg.steps && msg.steps.length > 0 && (
                <div className="mt-3 space-y-3">
                  {msg.steps.map((step, i) => (
                    <div key={i} className="p-3 bg-slate-900/50 border border-slate-800 rounded-xl">
                      <p className="text-xs italic text-slate-400 mb-2">"{step.thought}"</p>
                      {step.action && (
                        <div className="flex items-center gap-2 p-2 bg-indigo-500/10 rounded-lg border border-indigo-500/20">
                          <Play size={12} className="text-indigo-400" />
                          <span className="text-xs font-medium text-slate-200">{step.action.description}</span>
                          {step.action.status === 'success' && <CheckCircle size={12} className="ml-auto text-green-500" />}
                        </div>
                      )}

                      {step.requiresConfirmation && (
                        <div className="mt-3 flex gap-2">
                          <button 
                            onClick={onApproveAction}
                            className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white text-xs py-2 rounded-lg font-medium transition-colors"
                          >
                            Approve Action
                          </button>
                          <button 
                            onClick={onCancelAction}
                            className="px-3 bg-slate-800 hover:bg-slate-700 text-slate-300 text-xs py-2 rounded-lg font-medium transition-colors"
                          >
                            Cancel
                          </button>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}

        {status === AgentStatus.THINKING && (
          <div className="flex gap-3">
            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center shrink-0">
              <Bot size={16} />
            </div>
            <div className="bg-slate-900 border border-slate-800 p-3 rounded-2xl rounded-tl-none flex items-center gap-3">
              <Loader2 size={16} className="animate-spin text-indigo-500" />
              <span className="text-sm text-slate-400">Planning next steps...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-4 bg-slate-900/50 border-t border-slate-800">
        <form onSubmit={handleSubmit} className="relative">
          <textarea
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            disabled={status !== AgentStatus.IDLE}
            placeholder={status === AgentStatus.IDLE ? "Tell Nexus what to do..." : "Waiting for current task..."}
            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 pr-12 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600/50 transition-all resize-none min-h-[100px]"
          />
          <button
            type="submit"
            disabled={status !== AgentStatus.IDLE || !inputValue.trim()}
            className="absolute bottom-3 right-3 p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </form>
        <div className="mt-3 flex items-center gap-2 px-1">
          <div className="flex gap-1">
            <div className="w-1 h-1 rounded-full bg-slate-600"></div>
            <div className="w-1 h-1 rounded-full bg-slate-600"></div>
          </div>
          <span className="text-[10px] text-slate-500 font-medium uppercase tracking-tight">AI may take several minutes for complex workflows</span>
        </div>
      </div>
    </div>
  );
};

export default AgentControl;

import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import VirtualLaptop from './components/VirtualLaptop';
import AgentControl from './components/AgentControl';
import { AgentStatus, Message, AgentAction, AgentStep } from './types';
import { getNextAgentStep } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'system',
      content: 'Welcome to Nexus. I am ready to assist with your workflows. I can navigate the web, manage code, and handle integrations.',
      timestamp: Date.now()
    }
  ]);
  const [status, setStatus] = useState<AgentStatus>(AgentStatus.IDLE);
  const [currentAction, setCurrentAction] = useState<AgentAction | null>(null);

  const executeAction = useCallback(async (step: AgentStep) => {
    if (!step.action) return;

    setStatus(AgentStatus.EXECUTING);
    setCurrentAction({ ...step.action, status: 'active' });

    // Simulate action execution time
    await new Promise(resolve => setTimeout(resolve, 3000));

    setCurrentAction({ ...step.action, status: 'success' });

    // In a real app, we'd check if more steps are needed
    // For this demo, we'll finish after one or check logic
    setStatus(AgentStatus.IDLE);
    setCurrentAction(null);

    setMessages(prev => prev.map(m => {
       if (m.steps?.some(s => s.action?.id === step.action?.id)) {
          return {
             ...m,
             steps: m.steps?.map(s => s.action?.id === step.action?.id ? { ...s, action: { ...s.action!, status: 'success' } } : s)
          };
       }
       return m;
    }));
  }, []);

  const handleSendMessage = async (content: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setStatus(AgentStatus.THINKING);

    try {
      // Logic for reasoning
      const step = await getNextAgentStep(content, messages.slice(-5));

      const agentMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'agent',
        content: `I'll help with that. I've planned the following:`,
        steps: [step],
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, agentMsg]);

      if (step.requiresConfirmation) {
        setStatus(AgentStatus.WAITING_FOR_USER);
      } else {
        await executeAction(step);
      }
    } catch (error) {
      console.error(error);
      setStatus(AgentStatus.IDLE);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        content: 'Sorry, I encountered an error processing that request.',
        timestamp: Date.now()
      }]);
    }
  };

  const handleApproveAction = () => {
    const lastMsgWithStep = [...messages].reverse().find(m => m.steps && m.steps.length > 0);
    const step = lastMsgWithStep?.steps?.[0];
    if (step) {
      executeAction(step);
    }
  };

  const handleCancelAction = () => {
    setStatus(AgentStatus.IDLE);
    setCurrentAction(null);
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'system',
      content: 'Action cancelled by user.',
      timestamp: Date.now()
    }]);
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 overflow-hidden">
      <Sidebar />
      <main className="flex-1 flex flex-col min-w-0">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/20 glass sticky top-0 z-10">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
              <h1 className="text-sm font-semibold text-slate-200">Session #7192 - Web Automation</h1>
            </div>
            <div className="h-4 w-px bg-slate-800"></div>
            <div className="text-[10px] bg-indigo-500/10 text-indigo-400 px-2 py-0.5 rounded border border-indigo-500/20 font-bold uppercase">Pro Tier</div>
          </div>
          <div className="flex items-center gap-3">
            <div className="text-right mr-3">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Runtime</p>
              <p className="text-xs font-mono text-slate-300">01:24:55</p>
            </div>
            <button className="px-4 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-semibold rounded-lg transition-colors border border-slate-700">
              Snapshot
            </button>
            <button className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-semibold rounded-lg transition-colors shadow-lg shadow-indigo-600/20">
              Collaborate
            </button>
          </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
          <VirtualLaptop currentAction={currentAction} />
          <AgentControl 
            messages={messages} 
            status={status}
            onSendMessage={handleSendMessage}
            onApproveAction={handleApproveAction}
            onCancelAction={handleCancelAction}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Search, RotateCcw, ChevronLeft, ChevronRight, Share2, Plus, Terminal as TerminalIcon, MousePointer2, Type } from 'lucide-react';
import { AgentAction } from '../types';

interface VirtualLaptopProps {
  currentAction: AgentAction | null;
}

const VirtualLaptop: React.FC<VirtualLaptopProps> = ({ currentAction }) => {
  const [url, setUrl] = useState('https://github.com/trending');
  const [terminalLines, setTerminalLines] = useState<string[]>(['Nexus OS v1.0.4', 'Checking connectivity...', 'All systems green.']);
  const [browserLoading, setBrowserLoading] = useState(false);
  const [cursorPos, setCursorPos] = useState({ x: 50, y: 50 });
  const [ripples, setRipples] = useState<{id: number, x: number, y: number}[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  const [typedText, setTypedText] = useState('');

  const browserRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!currentAction) {
      setIsTyping(false);
      return;
