import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AgentStep, GroundingChunk } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const AGENT_SYSTEM_PROMPT = `
You are Nexus, an autonomous AI Agent.
Analyze user input and determine if they want a direct answer (CHAT) or a workflow execution (WORKFLOW).
For WORKFLOWs: Provide thought and action.
For CHAT: Provide direct content.
Available tools: Browser (Navigate, Click, Type), Terminal, Integrations.
`;

const actionSchema = {
  type: Type.OBJECT,
  properties: {
    intent: { type: Type.STRING, description: "CHAT or WORKFLOW" },
    thought: { type: Type.STRING },
    action: {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING },
        description: { type: Type.STRING },
        payload: { type: Type.STRING },
        requiresConfirmation: { type: Type.BOOLEAN }
      }
    },
    content: { type: Type.STRING, description: "Direct answer for CHAT intent" }
  },
  required: ["intent", "thought"]
};

// Use Flash Lite for fast intent classification or simple tasks
export const fastQuery = async (prompt: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: prompt
  });
  return response.text || "";
};

// Use Thinking Mode for complex reasoning
export const deepReasoningQuery = async (prompt: string, history: any[]): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.content }] })),
      { role: 'user', parts: [{ text: prompt }] }
    ],
    config: {
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });
  return response.text || "";
};

// Use Search Grounding for current events
export const searchGroundingQuery = async (prompt: string): Promise<{ text: string, sources: GroundingChunk[] }> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  return { text: response.text || "", sources };
};

export const processUserIntent = async (prompt: string, history: any[]): Promise<any> => {
  // First, use Flash Lite to decide if it's complex or needs search
  const classifier = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: `Classify the following request: "${prompt}". 
    Is it: 
    1. "SEARCH" (needs current news/web data)
    2. "COMPLEX" (needs deep logic/coding)
    3. "WORKFLOW" (needs browser/terminal automation)
    4. "CHAT" (simple question)
    Return ONLY the category name.`,
  });

  const category = classifier.text.trim().toUpperCase();

  if (category.includes("SEARCH")) {
    return { intent: 'CHAT', ...(await searchGroundingQuery(prompt)) };
  }

  if (category.includes("COMPLEX")) {
    const text = await deepReasoningQuery(prompt, history);
    return { intent: 'CHAT', content: text, isThinking: true };
  }

  // Default behavior for WORKFLOW or CHAT
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [
      { role: 'user', parts: [{ text: `History: ${JSON.stringify(history.slice(-3))} \n\nInput: ${prompt}` }] }
    ],
    config: {
      systemInstruction: AGENT_SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: actionSchema,
    },
  });

  return JSON.parse(response.text || "{}");
};

