    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  return { text: response.text || "", sources };
};

export const processUserIntent = async (prompt: string, history: any[]): Promise<any> => {
  const classifier = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: `Classify the following request: "${prompt}". 
    Is it: 
    1. "SEARCH" (needs current news/web data)
    2. "COMPLEX" (needs deep logic/coding)
    3. "WORKFLOW" (needs browser/terminal automation)
    4. "CHAT" (simple question)
    Return ONLY the category name.`,
  });

  const category = classifier.text.trim().toUpperCase();

  if (category.includes("SEARCH")) {
    return { intent: 'CHAT', ...(await searchGroundingQuery(prompt)) };
  }

  if (category.includes("COMPLEX")) {
    const text = await deepReasoningQuery(prompt, history);
    return { intent: 'CHAT', content: text, isThinking: true };
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [
      { role: 'user', parts: [{ text: `History: ${JSON.stringify(history.slice(-3))} \n\nInput: ${prompt}` }] }
    ],
    config: {
      systemInstruction: AGENT_SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: actionSchema,
    },
  });

  return JSON.parse(response.text || "{}");
};

