import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import VirtualLaptop from './components/VirtualLaptop';
import AgentControl from './components/AgentControl';
import { AgentStatus, Message, AgentAction, AgentStep, BrowserPage } from './types';
import { processUserIntent, generateMockPage } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'system',
      content: 'Nexus OS Active. Simulated environment ready. Try asking me to "Visit apple.com" or "Find the latest news on Google".',
      timestamp: Date.now()
    }
  ]);
  const [status, setStatus] = useState<AgentStatus>(AgentStatus.IDLE);
  const [currentAction, setCurrentAction] = useState<AgentAction | null>(null);
  const [browserPage, setBrowserPage] = useState<BrowserPage | null>(null);

  // Initialize with a default page
  useEffect(() => {
    handleManualNavigate('https://google.com');
  }, []);

  const handleManualNavigate = async (url: string) => {
    try {
      const page = await generateMockPage(url);
      setBrowserPage(page);
    } catch (e) {
      console.error("Navigation failed", e);
    }
  };

  const executeAction = useCallback(async (step: AgentStep) => {
    if (!step.action) return;

    setStatus(AgentStatus.EXECUTING);
    setCurrentAction({ ...step.action, status: 'active' });

    if (step.action.type === 'BROWSER_NAVIGATE') {
      const page = await generateMockPage(step.action.payload);
      setBrowserPage(page);
      await new Promise(resolve => setTimeout(resolve, 1500));
    } else {
      await new Promise(resolve => setTimeout(resolve, 2000));
    }

    setCurrentAction({ ...step.action, status: 'success' });
    setStatus(AgentStatus.IDLE);
    setCurrentAction(null);

    setMessages(prev => prev.map(m => {
       if (m.steps?.some(s => s.action?.id === step.action?.id)) {
          return {
             ...m,
             steps: m.steps?.map(s => s.action?.id === step.action?.id ? { ...s, action: { ...s.action!, status: 'success' } } : s)
          };
       }
       return m;
    }));
  }, []);

  const handleSendMessage = async (content: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setStatus(AgentStatus.THINKING);

    try {
      const result = await processUserIntent(content, messages);

      const agentMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'agent',
        content: result.content || (result.intent === 'CHAT' ? result.text : "Working on that. Executing browser sequence..."),
        isThinking: !!result.isThinking,
        groundingSources: result.sources || [],
        steps: result.intent === 'WORKFLOW' ? [{
          thought: result.thought,
          action: result.action ? {
            id: Math.random().toString(36).substr(2, 9),
            ...result.action,
            status: 'pending',
            timestamp: Date.now()
          } : undefined,
          requiresConfirmation: result.action?.requiresConfirmation
        }] : [],
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, agentMsg]);

      if (result.intent === 'WORKFLOW' && agentMsg.steps?.[0]) {
        const step = agentMsg.steps[0];
        if (step.requiresConfirmation) {
          setStatus(AgentStatus.WAITING_FOR_USER);
        } else if (step.action) {
          await executeAction(step);
        } else {
          setStatus(AgentStatus.IDLE);
        }
      } else {
        setStatus(AgentStatus.IDLE);
      }
    } catch (error) {
      console.error(error);
      setStatus(AgentStatus.IDLE);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        content: 'System Error: Routing failed. Please try again.',
        timestamp: Date.now()
      }]);
    }
  };

  const handleApproveAction = () => {
    const lastMsgWithStep = [...messages].reverse().find(m => m.steps && m.steps.length > 0);
    const step = lastMsgWithStep?.steps?.[0];
    if (step) {
      executeAction(step);
    }
  };

  const handleCancelAction = () => {
    setStatus(AgentStatus.IDLE);
    setCurrentAction(null);
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role: 'system',
      content: 'Task halted by operator.',
      timestamp: Date.now()
    }]);
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 overflow-hidden select-none">
      <Sidebar />
      <main className="flex-1 flex flex-col min-w-0">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/40 backdrop-blur-xl sticky top-0 z-50">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <div className="w-2.5 h-2.5 rounded-full bg-indigo-500 shadow-[0_0_12px_rgba(99,102,241,0.8)] animate-pulse"></div>
              <h1 className="text-sm font-bold text-slate-200 tracking-tight">NEXUS_ENV_ALPHA</h1>
            </div>
            <div className="h-4 w-px bg-slate-800"></div>
            <div className="flex gap-2">
              <span className="text-[10px] bg-emerald-500/10 text-emerald-500 px-2 py-0.5 rounded border border-emerald-500/20 font-bold uppercase tracking-wider">Live Sim</span>
            </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="text-right">
              <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest leading-none mb-1">Agent Load</p>
              <div className="w-24 h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 w-1/4"></div>
              </div>
            </div>
            <button className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-[11px] font-bold rounded-lg transition-all shadow-lg active:scale-95">
              Reset Session
            </button>
          </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
          <VirtualLaptop 
            currentAction={currentAction} 
            pageContent={browserPage}
            onManualNavigate={handleManualNavigate}
          />
          <AgentControl 
            messages={messages} 
            status={status}
            onSendMessage={handleSendMessage}
            onApproveAction={handleApproveAction}
            onCancelAction={handleCancelAction}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

