    const trimmed = cmd.trim();
    if (!trimmed) return;

    setTerminalLines(prev => [...prev, `nexus@alpha:~$ ${trimmed}`]);

    // Command logic
    if (trimmed === 'clear') {
      setTerminalLines([]);
    } else if (trimmed === 'help') {
      setTerminalLines(prev => [...prev, 'Available commands:', ...COMMON_COMMANDS.map(c => ` - ${c}`)]);
    } else if (trimmed === 'status') {
      setTerminalLines(prev => [...prev, 'Nexus Node: Online', 'Uptime: 14h 22m', 'Load: 0.12, 0.08, 0.05']);
    } else if (trimmed === 'system-info') {
      setTerminalLines(prev => [...prev, 'OS: Nexus Runtime v1.0.4', 'Kernel: NodeX 5.15.0', 'Memory: 16GB Virtualized']);
    } else {
      setTerminalLines(prev => [...prev, `sh: command not found: ${trimmed.split(' ')[0]}`]);
    }

    setCommandHistory(prev => [trimmed, ...prev.filter(c => c !== trimmed)].slice(0, 50));
    setHistoryIndex(-1);
    setTerminalInput('');
  };

  const handleTerminalKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      executeTerminalCommand(terminalInput);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      const nextIndex = historyIndex + 1;
      if (nextIndex < commandHistory.length) {
        setHistoryIndex(nextIndex);
        setTerminalInput(commandHistory[nextIndex]);
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      const nextIndex = historyIndex - 1;
      if (nextIndex >= 0) {
        setHistoryIndex(nextIndex);
        setTerminalInput(commandHistory[nextIndex]);
      } else {
        setHistoryIndex(-1);
        setTerminalInput('');
      }
    } else if (e.key === 'Tab') {
      e.preventDefault();
      const input = terminalInput.toLowerCase();
      const match = COMMON_COMMANDS.find(cmd => cmd.startsWith(input));
      if (match) {
        setTerminalInput(match);
      }
    }
  };

  const renderElement = (el: BrowserElement, idx: number) => {
    switch (el.type) {
      case 'heading':
        return <h2 key={idx} className="text-3xl font-extrabold text-slate-900 mb-4">{el.content}</h2>;
      case 'text':
        return <p key={idx} className="text-slate-600 leading-relaxed mb-4">{el.content}</p>;
      case 'button':
        return <button key={idx} className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold text-sm hover:bg-indigo-700 transition-colors mr-3 mb-3 shadow-sm">{el.label}</button>;
      case 'input':
        return <input key={idx} type="text" placeholder={el.placeholder} className="w-full border border-slate-200 rounded-lg px-4 py-2 mb-4 bg-white shadow-inner focus:ring-2 focus:ring-indigo-500/20 outline-none" readOnly />;
      case 'link':
        return <a key={idx} href="#" className="text-indigo-600 underline font-medium mr-4 mb-3 inline-block">{el.label}</a>;
      case 'image':
        return <div key={idx} className="w-full h-48 bg-slate-200 rounded-xl mb-4 flex items-center justify-center text-slate-400 font-bold uppercase tracking-widest italic shadow-sm">Simulated Visual</div>;
      default:
        return null;
    }
  };

  return (
    <div className="flex-1 p-6 h-full overflow-hidden flex flex-col gap-6">
      <div className="flex-1 bg-slate-900 rounded-xl border border-slate-700 shadow-2xl flex flex-col overflow-hidden relative group">

        <form onSubmit={handleUrlSubmit} className="bg-slate-800 p-2 flex items-center gap-3 border-b border-slate-700 z-30">
          <div className="flex gap-1.5 px-2">
            <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-amber-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
          </div>
          <div className="flex gap-2">
            <ChevronLeft size={18} className="text-slate-500" />
            <ChevronRight size={18} className="text-slate-500" />
            <RotateCcw size={18} className={`${browserLoading ? 'animate-spin text-indigo-400' : 'text-slate-500'}`} />
          </div>
          <div className="flex-1 bg-slate-950/50 rounded-md border border-slate-700/50 px-3 py-1 flex items-center gap-2 relative overflow-hidden">
            <Search size={14} className="text-slate-500" />
            <input 
              value={urlInput}
              onChange={(e) => setUrlInput(e.target.value)}
              className="bg-transparent border-none outline-none text-xs text-slate-300 font-medium w-full"
            />
            {browserLoading && (
              <div className="absolute bottom-0 left-0 h-[2px] bg-indigo-500 w-full animate-pulse shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
            )}
          </div>
          <div className="flex gap-2 px-2 items-center">
             <div className="hidden sm:flex items-center gap-1 bg-slate-700/50 px-2 py-0.5 rounded text-[10px] text-slate-400 font-bold border border-slate-600">
                SECURE 1.3
             </div>
            <Share2 size={16} className="text-slate-500" />
            <Plus size={16} className="text-slate-500" />
          </div>
        </form>

        <div ref={browserRef} className="flex-1 bg-slate-50 overflow-auto text-slate-900 relative">

          {currentAction && (
            <div className="absolute top-6 left-6 z-40 flex flex-col gap-2">
              <div className="bg-slate-900/90 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold shadow-xl border border-white/10 flex items-center gap-3 backdrop-blur-md">
                 <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></div>
                 <span className="uppercase tracking-widest text-slate-400">Agent Status</span>
                 <span className="text-indigo-400">{currentAction.type}</span>
              </div>
            </div>
          )}

          {activeTarget && (
            <div className="absolute z-20 border-2 border-dashed border-indigo-500/40 rounded-lg pointer-events-none transition-all duration-700"
              style={{ left: `${activeTarget.x - 5}%`, top: `${activeTarget.y - 5}%`, width: '120px', height: '40px' }}
            />
          )}

          {currentAction?.type.startsWith('BROWSER_') && (
            <div className="absolute z-50 transition-all duration-1000 cubic-bezier(0.19, 1, 0.22, 1) pointer-events-none"
              style={{ left: `${cursorPos.x}%`, top: `${cursorPos.y}%` }}>
              <MousePointer2 size={22} className="text-slate-900 fill-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.3)] transform -rotate-12" />
            </div>
          )}

          {ripples.map(r => (
            <div key={r.id} className="absolute rounded-full border-2 border-indigo-500/60 pointer-events-none z-40 animate-[ripple_0.8s_ease-out]" 
              style={{ left: `${r.x}%`, top: `${r.y}%`, width: '40px', height: '40px', marginLeft: '-20px', marginTop: '-20px' }} />
          ))}

          <div className={`p-10 max-w-4xl mx-auto space-y-4 transition-all duration-500 ${browserLoading ? 'opacity-20 scale-95 blur-sm' : 'opacity-100 scale-100'}`}>
            {pageContent ? (
              <div className="animate-in fade-in zoom-in-95 duration-500">
                <div className="border-b border-slate-200 pb-6 mb-8 flex items-center gap-3">
                   <div className="p-3 bg-indigo-600 rounded-lg text-white shadow-lg">
                      <Globe size={24} />
                   </div>
                   <div>
                      <h1 className="text-2xl font-black text-slate-900 leading-none">{pageContent.title}</h1>
                      <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">{pageContent.url}</p>
                   </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12">
                   <div>{pageContent.elements.slice(0, Math.ceil(pageContent.elements.length / 2)).map(renderElement)}</div>
                   <div>{pageContent.elements.slice(Math.ceil(pageContent.elements.length / 2)).map(renderElement)}</div>
                </div>
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                 <div className="w-20 h-20 bg-slate-200 rounded-3xl animate-pulse mb-6"></div>
                 <div className="h-6 w-48 bg-slate-200 rounded mb-4 animate-pulse"></div>
                 <div className="h-4 w-64 bg-slate-100 rounded animate-pulse"></div>
              </div>
            )}
          </div>
        </div>
      </div>

      <div 
        className={`h-1/3 bg-slate-950 rounded-xl border transition-all duration-200 flex flex-col overflow-hidden font-mono text-sm relative ${terminalFocused ? 'border-indigo-500 shadow-[0_0_15px_rgba(99,102,241,0.2)]' : 'border-slate-800 shadow-xl'}`}
        onClick={() => terminalInputRef.current?.focus()}
      >
        <div className="bg-slate-900/80 px-4 py-2 border-b border-slate-800 flex items-center justify-between z-20 backdrop-blur-md">
          <div className="flex items-center gap-2 text-slate-400">
            <TerminalIcon size={14} className="text-emerald-500" />
            <span className="text-[10px] font-bold uppercase tracking-wider">nexus-core-runtime</span>
          </div>
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-1.5">
                <div className={`w-1.5 h-1.5 rounded-full animate-pulse ${terminalFocused ? 'bg-indigo-500' : 'bg-emerald-500'}`}></div>
                <span className="text-[9px] text-slate-500 font-bold">{terminalFocused ? 'INPUT ACTIVE' : 'READY'}</span>
             </div>
          </div>
        </div>

        <div 
          ref={terminalScrollRef}
          className="flex-1 p-5 text-emerald-500/90 overflow-y-auto space-y-1.5 scroll-smooth custom-scrollbar relative"
        >
          {terminalLines.map((line, i) => (
            <div key={i} className="flex gap-3 animate-in fade-in slide-in-from-left-1 duration-300">
              <span className="text-slate-700 select-none">[{new Date().toLocaleTimeString([], {hour12: false})}]</span>
              <span className={line.includes('nexus@alpha:~$') ? 'text-indigo-400 font-bold' : line.startsWith('>') ? 'text-indigo-400 font-bold' : line.startsWith('[PROCESS]') ? 'text-emerald-400' : 'text-emerald-500'}>
                {line}
              </span>
            </div>
          ))}

          {currentAction?.type === 'TERMINAL_COMMAND' && (
             <div className="flex gap-3 items-center">
                <span className="text-slate-700">[{new Date().toLocaleTimeString([], {hour12: false})}]</span>
                <span className="text-indigo-400 font-bold tracking-tight">
                  {'> '}
                  <span className="bg-indigo-500/10 px-1 rounded border-r-2 border-indigo-400 animate-[typing_0.8s_steps(40,end)]">
                    {currentAction.payload}
                  </span>
                </span>
             </div>
          )}

          {/* User Input Area */}
          <div className="flex gap-3 items-start relative group">
            <span className="text-slate-700 select-none">[{new Date().toLocaleTimeString([], {hour12: false})}]</span>
            <div className="flex-1 flex gap-2">
               <span className="text-indigo-400 font-bold">nexus@alpha:~$</span>
               <div className="flex-1 relative">
                 <textarea
                   ref={terminalInputRef}
                   value={terminalInput}
                   onChange={(e) => setTerminalInput(e.target.value)}
                   onKeyDown={handleTerminalKeyDown}
                   onFocus={() => setTerminalFocused(true)}
                   onBlur={() => setTerminalFocused(false)}
                   className="absolute inset-0 opacity-0 cursor-default resize-none focus:outline-none h-full w-full"
                   spellCheck={false}
                   autoComplete="off"
                 />
                 <div className="whitespace-pre-wrap break-all text-white min-h-[1.25rem] flex items-center">
                   {terminalInput}
                   <span className={`inline-block w-2 h-4 bg-emerald-500 ml-1 ${terminalFocused ? 'animate-blink' : 'opacity-50'}`}></span>
                 </div>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default VirtualLaptop;
